FUNCTION calculatePERT(optimistic, mostLikely, pessimistic)
 // PERT formula: (O + 4M + P) / 6
 optimisticWeight = optimistic
 mostLikelyWeight = 4 * mostLikely
 pessimisticWeight = pessimistic

 expectedValue = (optimisticWeight + mostLikelyWeight + pessimisticWeight) / 6
 standardDeviation = (pessimistic - optimistic) / 6

 RETURN expectedValue, standardDeviation
END FUNCTION

// Example usage:
// Optimistic = 100 hours, Most Likely = 120 hours, Pessimistic = 180 hours
// Expected = (100 + 480 + 180) / 6 = 126.67 hours
